// ===== Detail page JS =====
document.querySelectorAll('.detail-tab').forEach(tab=>tab.addEventListener('click',()=>{document.querySelectorAll('.detail-tab').forEach(t=>t.classList.remove('active'));document.querySelectorAll('.detail-panel').forEach(p=>p.classList.remove('active'));tab.classList.add('active');const panel=document.querySelector(`[data-detail-panel="${tab.dataset.detailTab}"]`);if(panel)panel.classList.add('active');}));
document.querySelectorAll('[data-timeline-filter]').forEach(tab=>tab.addEventListener('click',()=>{tab.parentElement.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));tab.classList.add('active');const filter=tab.dataset.timelineFilter;document.querySelectorAll('[data-event-type]').forEach(ev=>{ev.style.display=(filter==='all'||ev.dataset.eventType===filter)?'grid':'none';});}));
